import {
  compressTritonSelfSimilar,
  decompressTritonSelfSimilar,
  type Triton,
  type TritonSelfSimilarCompressionOptions,
  type TritonSelfSimilarPacket,
} from './unspeech-triton';

export interface UnicodeLexicon {
  codePoints: number[];
}

export interface Utf16Lexicon {
  codeUnits: number[];
}

export type UnicodeTeleportStrategy = 'direct' | 'direct-reordered' | 'residual';
export type UnicodeTeleportMode = 'auto' | UnicodeTeleportStrategy;
export type UnicodeReorderMode = 'none' | 'sorted' | 'auto';

export interface UnicodeTeleportOptions {
  baselineText?: string;
  mode?: UnicodeTeleportMode;
  reorderMode?: UnicodeReorderMode;
  tritonCompression?: TritonSelfSimilarCompressionOptions;
}

export interface UnicodeInflationOptions {
  baselineText?: string;
}

export interface UnicodeDirectTeleportPacket {
  strategy: 'direct';
  length: number;
  firstIndex: number;
  signPacket: TritonSelfSimilarPacket;
  magnitudeBytes: Uint8Array;
  estimatedPayloadBytes: number;
}

export interface UnicodeDirectReorderedTeleportPacket {
  strategy: 'direct-reordered';
  length: number;
  firstIndex: number;
  signPacket: TritonSelfSimilarPacket;
  magnitudeBytes: Uint8Array;
  /** For each reordered position i, the original sequence index before reordering. */
  permutationBytes: Uint8Array;
  estimatedPayloadBytes: number;
}

export interface UnicodeResidualTeleportPacket {
  strategy: 'residual';
  baselineLength: number;
  targetLength: number;
  patchCount: number;
  patchBytes: Uint8Array;
  estimatedPayloadBytes: number;
}

export type UnicodeTeleportPacket =
  | UnicodeDirectTeleportPacket
  | UnicodeDirectReorderedTeleportPacket
  | UnicodeResidualTeleportPacket;

export interface UnicodeStructuralPacket {
  strategy: 'structural-unordered';
  totalSymbols: number;
  nonZeroBuckets: number;
  bucketBytes: Uint8Array;
  estimatedPayloadBytes: number;
}

export interface UnicodeTeleportShootoutOptions {
  baselineText?: string;
  tritonCompression?: TritonSelfSimilarCompressionOptions;
  includeStructural?: boolean;
  includeReordered?: boolean;
}

export interface UnicodeTeleportShootoutEntry {
  strategy:
    | UnicodeTeleportStrategy
    | UnicodeStructuralPacket['strategy'];
  estimatedPayloadBytes: number;
  preservesOrder: boolean;
  packet: UnicodeTeleportPacket | UnicodeStructuralPacket;
}

export interface UnicodeTeleportShootoutResult {
  entries: UnicodeTeleportShootoutEntry[];
  bestLossless: UnicodeTeleportShootoutEntry;
  bestAny: UnicodeTeleportShootoutEntry;
}

interface VarUintRead {
  value: number;
  nextOffset: number;
}

function writeVarUint(output: number[], value: number): void {
  if (!Number.isInteger(value) || value < 0) {
    throw new RangeError(`varuint must be a non-negative integer, received ${value}`);
  }
  let remainder = value;
  do {
    let byte = remainder % 128;
    remainder = Math.floor(remainder / 128);
    if (remainder > 0) byte += 128;
    output.push(byte);
  } while (remainder > 0);
}

function readVarUint(input: Uint8Array, startOffset: number): VarUintRead {
  let value = 0;
  let factor = 1;
  let offset = startOffset;
  for (let i = 0; i < 8; i++) {
    if (offset >= input.length) {
      throw new RangeError('unexpected end of payload while reading varuint');
    }
    const byte = input[offset]!;
    offset += 1;
    value += (byte & 0x7f) * factor;
    if ((byte & 0x80) === 0) {
      return { value, nextOffset: offset };
    }
    factor *= 128;
  }
  throw new RangeError('varuint exceeds supported length');
}

function buildValueIndexMap(values: readonly number[]): Map<number, number> {
  const out = new Map<number, number>();
  for (let i = 0; i < values.length; i++) {
    out.set(values[i]!, i);
  }
  return out;
}

function buildLexiconIndexMap(lexicon: UnicodeLexicon): Map<number, number> {
  return buildValueIndexMap(lexicon.codePoints);
}

function buildUtf16LexiconIndexMap(lexicon: Utf16Lexicon): Map<number, number> {
  return buildValueIndexMap(lexicon.codeUnits);
}

function encodeDirectSign(diff: number): Triton {
  if (diff < 0) return -1;
  if (diff > 0) return 1;
  return 0;
}

function decodeDirectSign(sign: Triton, magnitude: number): number {
  if (sign === -1) return -magnitude;
  if (sign === 1) return magnitude;
  return 0;
}

function validateLexiconIndex(index: number, lexiconSize: number): void {
  if (!Number.isInteger(index) || index < 0 || index >= lexiconSize) {
    throw new RangeError(
      `lexicon index out of bounds: index=${index}, lexiconSize=${lexiconSize}`
    );
  }
}

function projectCodePointsToLexiconIndices(
  codePoints: readonly number[],
  lexicon: UnicodeLexicon
): number[] {
  const indexMap = buildLexiconIndexMap(lexicon);
  const indices: number[] = [];
  for (const codePoint of codePoints) {
    const index = indexMap.get(codePoint);
    if (index === undefined) {
      throw new RangeError(
        `codepoint ${codePoint} is absent from shared lexicon`
      );
    }
    indices.push(index);
  }
  return indices;
}

function inflateLexiconIndicesToCodePoints(
  indices: readonly number[],
  lexicon: UnicodeLexicon
): number[] {
  const out: number[] = [];
  for (const index of indices) {
    validateLexiconIndex(index, lexicon.codePoints.length);
    out.push(lexicon.codePoints[index]!);
  }
  return out;
}

function projectUtf16UnitsToLexiconIndices(
  units: readonly number[],
  lexicon: Utf16Lexicon
): number[] {
  const indexMap = buildUtf16LexiconIndexMap(lexicon);
  const indices: number[] = [];
  for (const unit of units) {
    const index = indexMap.get(unit);
    if (index === undefined) {
      throw new RangeError(`UTF-16 code unit ${unit} is absent from shared lexicon`);
    }
    indices.push(index);
  }
  return indices;
}

function inflateLexiconIndicesToUtf16Units(
  indices: readonly number[],
  lexicon: Utf16Lexicon
): number[] {
  const out: number[] = [];
  for (const index of indices) {
    validateLexiconIndex(index, lexicon.codeUnits.length);
    out.push(lexicon.codeUnits[index]!);
  }
  return out;
}

async function encodeDirectTeleportPacket(
  indices: readonly number[],
  tritonCompression: TritonSelfSimilarCompressionOptions
): Promise<UnicodeDirectTeleportPacket> {
  if (indices.length === 0) {
    const signPacket = await compressTritonSelfSimilar([], tritonCompression);
    return {
      strategy: 'direct',
      length: 0,
      firstIndex: 0,
      signPacket,
      magnitudeBytes: new Uint8Array(0),
      estimatedPayloadBytes: signPacket.payloadLength,
    };
  }

  const signs: Triton[] = [];
  const magnitudes: number[] = [];
  for (let i = 1; i < indices.length; i++) {
    const diff = indices[i]! - indices[i - 1]!;
    signs.push(encodeDirectSign(diff));
    writeVarUint(magnitudes, Math.abs(diff));
  }

  const signPacket = await compressTritonSelfSimilar(signs, tritonCompression);
  const magnitudeBytes = new Uint8Array(magnitudes);
  return {
    strategy: 'direct',
    length: indices.length,
    firstIndex: indices[0]!,
    signPacket,
    magnitudeBytes,
    estimatedPayloadBytes: signPacket.payloadLength + magnitudeBytes.length + 8,
  };
}

async function decodeDirectTeleportPacket(
  packet: UnicodeDirectTeleportPacket
): Promise<number[]> {
  if (packet.length === 0) return [];

  const signs = await decompressTritonSelfSimilar(packet.signPacket);
  const requiredSteps = packet.length - 1;
  if (signs.length !== requiredSteps) {
    throw new RangeError(
      `direct sign length mismatch: expected ${requiredSteps}, received ${signs.length}`
    );
  }

  const magnitudes: number[] = [];
  let offset = 0;
  for (let i = 0; i < requiredSteps; i++) {
    const decoded = readVarUint(packet.magnitudeBytes, offset);
    magnitudes.push(decoded.value);
    offset = decoded.nextOffset;
  }
  if (offset !== packet.magnitudeBytes.length) {
    throw new RangeError('unexpected trailing bytes in direct magnitude stream');
  }

  const indices: number[] = [packet.firstIndex];
  for (let i = 0; i < requiredSteps; i++) {
    const prev = indices[i]!;
    const delta = decodeDirectSign(signs[i]!, magnitudes[i]!);
    const next = prev + delta;
    if (next < 0) {
      throw new RangeError(`decoded negative lexicon index at step ${i}: ${next}`);
    }
    indices.push(next);
  }
  return indices;
}

function chooseSortedReordering(
  indices: readonly number[]
): { reordered: number[]; permutation: number[] } {
  const tagged = indices.map((index, originalPosition) => ({
    index,
    originalPosition,
  }));
  tagged.sort(
    (a, b) => a.index - b.index || a.originalPosition - b.originalPosition
  );
  return {
    reordered: tagged.map((entry) => entry.index),
    permutation: tagged.map((entry) => entry.originalPosition),
  };
}

function encodePermutation(permutation: readonly number[]): Uint8Array {
  const out: number[] = [];
  for (const value of permutation) writeVarUint(out, value);
  return new Uint8Array(out);
}

function decodePermutation(
  bytes: Uint8Array,
  length: number
): number[] {
  const out: number[] = [];
  let offset = 0;
  for (let i = 0; i < length; i++) {
    const decoded = readVarUint(bytes, offset);
    out.push(decoded.value);
    offset = decoded.nextOffset;
  }
  if (offset !== bytes.length) {
    throw new RangeError('unexpected trailing bytes in permutation stream');
  }

  const seen = new Uint8Array(length);
  for (const index of out) {
    if (index < 0 || index >= length) {
      throw new RangeError(
        `permutation index out of bounds: index=${index}, length=${length}`
      );
    }
    if (seen[index] === 1) {
      throw new RangeError(`permutation contains duplicate index ${index}`);
    }
    seen[index] = 1;
  }
  return out;
}

async function encodeDirectReorderedTeleportPacket(
  indices: readonly number[],
  tritonCompression: TritonSelfSimilarCompressionOptions
): Promise<UnicodeDirectReorderedTeleportPacket> {
  const { reordered, permutation } = chooseSortedReordering(indices);
  const direct = await encodeDirectTeleportPacket(reordered, tritonCompression);
  const permutationBytes = encodePermutation(permutation);
  return {
    strategy: 'direct-reordered',
    length: direct.length,
    firstIndex: direct.firstIndex,
    signPacket: direct.signPacket,
    magnitudeBytes: direct.magnitudeBytes,
    permutationBytes,
    estimatedPayloadBytes:
      direct.estimatedPayloadBytes + permutationBytes.length + 4,
  };
}

async function decodeDirectReorderedTeleportPacket(
  packet: UnicodeDirectReorderedTeleportPacket
): Promise<number[]> {
  if (packet.length === 0) return [];

  const reordered = await decodeDirectTeleportPacket({
    strategy: 'direct',
    length: packet.length,
    firstIndex: packet.firstIndex,
    signPacket: packet.signPacket,
    magnitudeBytes: packet.magnitudeBytes,
    estimatedPayloadBytes: packet.estimatedPayloadBytes,
  });
  const permutation = decodePermutation(packet.permutationBytes, packet.length);
  if (permutation.length !== reordered.length) {
    throw new RangeError(
      `reordered length mismatch: permutation=${permutation.length}, payload=${reordered.length}`
    );
  }

  const out = new Array<number>(packet.length).fill(-1);
  for (let i = 0; i < packet.length; i++) {
    const originalPosition = permutation[i]!;
    out[originalPosition] = reordered[i]!;
  }
  for (let i = 0; i < out.length; i++) {
    if (out[i] === -1) {
      throw new RangeError(`missing restored index at position ${i}`);
    }
  }
  return out;
}

interface TeleportSelectionInput {
  targetIndices: readonly number[];
  baselineIndices: readonly number[] | null;
  mode: UnicodeTeleportMode;
  reorderMode: UnicodeReorderMode;
  tritonCompression: TritonSelfSimilarCompressionOptions;
}

async function chooseTeleportPacket(
  input: TeleportSelectionInput
): Promise<UnicodeTeleportPacket> {
  const {
    targetIndices,
    baselineIndices,
    mode,
    reorderMode,
    tritonCompression,
  } = input;

  const direct = await encodeDirectTeleportPacket(targetIndices, tritonCompression);
  const directReordered =
    mode === 'direct-reordered' ||
    reorderMode === 'sorted' ||
    reorderMode === 'auto'
      ? await encodeDirectReorderedTeleportPacket(targetIndices, tritonCompression)
      : null;

  if (mode === 'direct') return direct;
  if (mode === 'direct-reordered') {
    if (!directReordered) {
      throw new Error('direct-reordered mode requires reorder packet');
    }
    return directReordered;
  }
  if (mode !== 'auto' && mode !== 'residual') {
    throw new Error(`unsupported teleport mode ${String(mode)}`);
  }

  if (!baselineIndices) {
    if (mode === 'residual') {
      throw new Error('residual teleport mode requires baselineText');
    }
    if (reorderMode === 'sorted') {
      if (!directReordered) {
        throw new Error('sorted reorder mode requires reorder packet');
      }
      return directReordered;
    }
    if (reorderMode === 'none' || !directReordered) {
      return direct;
    }
    return directReordered.estimatedPayloadBytes < direct.estimatedPayloadBytes
      ? directReordered
      : direct;
  }

  const residual = encodeResidualTeleportPacket(targetIndices, baselineIndices);
  if (mode === 'residual') return residual;

  const candidates: UnicodeTeleportPacket[] = [residual];
  if (reorderMode === 'sorted') {
    candidates.push(directReordered ?? direct);
  } else if (reorderMode === 'auto') {
    candidates.push(direct);
    if (directReordered) candidates.push(directReordered);
  } else {
    candidates.push(direct);
  }

  return candidates.reduce((best, next) =>
    next.estimatedPayloadBytes < best.estimatedPayloadBytes ? next : best
  );
}

async function decodeTeleportPacketToIndices(
  packet: UnicodeTeleportPacket,
  baselineIndices: readonly number[] | null
): Promise<number[]> {
  if (packet.strategy === 'direct') {
    return decodeDirectTeleportPacket(packet);
  }
  if (packet.strategy === 'direct-reordered') {
    return decodeDirectReorderedTeleportPacket(packet);
  }
  if (!baselineIndices) {
    throw new Error('residual inflation requires baselineText');
  }
  return decodeResidualTeleportPacket(packet, baselineIndices);
}

function encodeResidualTeleportPacket(
  targetIndices: readonly number[],
  baselineIndices: readonly number[]
): UnicodeResidualTeleportPacket {
  const patchBytes: number[] = [];
  let patchCount = 0;

  for (let position = 0; position < targetIndices.length; position++) {
    const target = targetIndices[position]!;
    const base = position < baselineIndices.length ? baselineIndices[position]! : -1;
    if (target !== base) {
      writeVarUint(patchBytes, position);
      writeVarUint(patchBytes, target);
      patchCount += 1;
    }
  }

  return {
    strategy: 'residual',
    baselineLength: baselineIndices.length,
    targetLength: targetIndices.length,
    patchCount,
    patchBytes: new Uint8Array(patchBytes),
    estimatedPayloadBytes: patchBytes.length + 10,
  };
}

function decodeResidualTeleportPacket(
  packet: UnicodeResidualTeleportPacket,
  baselineIndices: readonly number[]
): number[] {
  const out = baselineIndices.slice(0, packet.targetLength);
  while (out.length < packet.targetLength) out.push(0);

  let offset = 0;
  for (let i = 0; i < packet.patchCount; i++) {
    const pos = readVarUint(packet.patchBytes, offset);
    offset = pos.nextOffset;
    const idx = readVarUint(packet.patchBytes, offset);
    offset = idx.nextOffset;

    if (pos.value >= packet.targetLength) {
      throw new RangeError(
        `residual patch position ${pos.value} exceeds targetLength ${packet.targetLength}`
      );
    }
    out[pos.value] = idx.value;
  }

  if (offset !== packet.patchBytes.length) {
    throw new RangeError('unexpected trailing bytes in residual patch stream');
  }

  return out;
}

function encodeStructuralPacketFromIndices(
  indices: readonly number[],
  lexiconSize: number
): UnicodeStructuralPacket {
  const counts = new Map<number, number>();
  for (const index of indices) {
    validateLexiconIndex(index, lexiconSize);
    counts.set(index, (counts.get(index) ?? 0) + 1);
  }

  const entries = [...counts.entries()].sort((a, b) => a[0] - b[0]);
  const bucketBytes: number[] = [];
  for (const [index, count] of entries) {
    writeVarUint(bucketBytes, index);
    writeVarUint(bucketBytes, count);
  }

  return {
    strategy: 'structural-unordered',
    totalSymbols: indices.length,
    nonZeroBuckets: entries.length,
    bucketBytes: new Uint8Array(bucketBytes),
    estimatedPayloadBytes: bucketBytes.length + 8,
  };
}

function decodeStructuralPacketToIndices(
  packet: UnicodeStructuralPacket,
  lexiconSize: number
): number[] {
  const indices: number[] = [];
  let offset = 0;
  for (let i = 0; i < packet.nonZeroBuckets; i++) {
    const indexField = readVarUint(packet.bucketBytes, offset);
    offset = indexField.nextOffset;
    const countField = readVarUint(packet.bucketBytes, offset);
    offset = countField.nextOffset;

    validateLexiconIndex(indexField.value, lexiconSize);
    if (countField.value <= 0) {
      throw new RangeError(
        `structural bucket count must be positive, received ${countField.value}`
      );
    }
    for (let j = 0; j < countField.value; j++) {
      indices.push(indexField.value);
    }
  }
  if (offset !== packet.bucketBytes.length) {
    throw new RangeError('unexpected trailing bytes in structural bucket stream');
  }
  if (indices.length !== packet.totalSymbols) {
    throw new RangeError(
      `structural symbol count mismatch: expected ${packet.totalSymbols}, received ${indices.length}`
    );
  }
  return indices;
}

/**
 * Handles the gnosis text To Code Point Vector workflow.
 */
export function textToCodePointVector(text: string): number[] {
  const out: number[] = [];
  for (const symbol of text) {
    const codePoint = symbol.codePointAt(0);
    if (codePoint === undefined) {
      throw new RangeError('encountered empty Unicode symbol while vectorizing text');
    }
    out.push(codePoint);
  }
  return out;
}

/**
 * Handles the gnosis code Point Vector To Text workflow.
 */
export function codePointVectorToText(codePoints: readonly number[]): string {
  let out = '';
  for (const codePoint of codePoints) {
    if (!Number.isInteger(codePoint) || codePoint < 0 || codePoint > 0x10ffff) {
      throw new RangeError(`invalid Unicode codepoint ${codePoint}`);
    }
    out += String.fromCodePoint(codePoint);
  }
  return out;
}

/**
 * Handles the gnosis text To Utf16 Vector workflow.
 */
export function textToUtf16Vector(text: string): number[] {
  const out: number[] = [];
  for (let i = 0; i < text.length; i++) {
    out.push(text.charCodeAt(i));
  }
  return out;
}

/**
 * Handles the gnosis utf16 Vector To Text workflow.
 */
export function utf16VectorToText(codeUnits: readonly number[]): string {
  let out = '';
  for (const unit of codeUnits) {
    if (!Number.isInteger(unit) || unit < 0 || unit > 0xffff) {
      throw new RangeError(`invalid UTF-16 code unit ${unit}`);
    }
    out += String.fromCharCode(unit);
  }
  return out;
}

/**
 * Builds the Unicode Lexicon.
 */
export function buildUnicodeLexicon(texts: readonly string[]): UnicodeLexicon {
  const set = new Set<number>();
  for (const text of texts) {
    for (const codePoint of textToCodePointVector(text)) {
      set.add(codePoint);
    }
  }
  return {
    codePoints: [...set].sort((a, b) => a - b),
  };
}

/**
 * Builds the Utf16 Lexicon.
 */
export function buildUtf16Lexicon(texts: readonly string[]): Utf16Lexicon {
  const set = new Set<number>();
  for (const text of texts) {
    for (const unit of textToUtf16Vector(text)) {
      set.add(unit);
    }
  }
  return {
    codeUnits: [...set].sort((a, b) => a - b),
  };
}

/**
 * Handles the gnosis inflate Text From Lexicon Indices workflow.
 */
export function inflateTextFromLexiconIndices(
  indices: readonly number[],
  lexicon: UnicodeLexicon
): string {
  const codePoints = inflateLexiconIndicesToCodePoints(indices, lexicon);
  return codePointVectorToText(codePoints);
}

/**
 * Handles the gnosis project Text To Lexicon Indices workflow.
 */
export function projectTextToLexiconIndices(
  text: string,
  lexicon: UnicodeLexicon
): number[] {
  const codePoints = textToCodePointVector(text);
  return projectCodePointsToLexiconIndices(codePoints, lexicon);
}

/**
 * Handles the gnosis project Text To Utf16 Lexicon Indices workflow.
 */
export function projectTextToUtf16LexiconIndices(
  text: string,
  lexicon: Utf16Lexicon
): number[] {
  const units = textToUtf16Vector(text);
  return projectUtf16UnitsToLexiconIndices(units, lexicon);
}

/**
 * Handles the gnosis teleport Unicode Through Lexicon workflow.
 */
export async function teleportUnicodeThroughLexicon(
  text: string,
  lexicon: UnicodeLexicon,
  options: UnicodeTeleportOptions = {}
): Promise<UnicodeTeleportPacket> {
  const mode = options.mode ?? 'auto';
  const reorderMode = options.reorderMode ?? 'auto';
  const tritonCompression = options.tritonCompression ?? {
    motifSize: 5,
    useBitwiseFold: true,
    preferSmallerPayload: true,
  };

  const targetIndices = projectTextToLexiconIndices(text, lexicon);
  const baselineIndices = options.baselineText
    ? projectTextToLexiconIndices(options.baselineText, lexicon)
    : null;
  return chooseTeleportPacket({
    targetIndices,
    baselineIndices,
    mode,
    reorderMode,
    tritonCompression,
  });
}

/**
 * Handles the gnosis inflate Unicode From Teleport workflow.
 */
export async function inflateUnicodeFromTeleport(
  packet: UnicodeTeleportPacket,
  lexicon: UnicodeLexicon,
  options: UnicodeInflationOptions = {}
): Promise<string> {
  const baselineIndices = options.baselineText
    ? projectTextToLexiconIndices(options.baselineText, lexicon)
    : null;
  const indices = await decodeTeleportPacketToIndices(packet, baselineIndices);

  for (const index of indices) {
    validateLexiconIndex(index, lexicon.codePoints.length);
  }

  return inflateTextFromLexiconIndices(indices, lexicon);
}

/**
 * Handles the gnosis inflate Text From Utf16 Lexicon Indices workflow.
 */
export function inflateTextFromUtf16LexiconIndices(
  indices: readonly number[],
  lexicon: Utf16Lexicon
): string {
  const units = inflateLexiconIndicesToUtf16Units(indices, lexicon);
  return utf16VectorToText(units);
}

/**
 * Handles the gnosis teleport Utf16 Through Lexicon workflow.
 */
export async function teleportUtf16ThroughLexicon(
  text: string,
  lexicon: Utf16Lexicon,
  options: UnicodeTeleportOptions = {}
): Promise<UnicodeTeleportPacket> {
  const mode = options.mode ?? 'auto';
  const reorderMode = options.reorderMode ?? 'auto';
  const tritonCompression = options.tritonCompression ?? {
    motifSize: 5,
    useBitwiseFold: true,
    preferSmallerPayload: true,
  };
  const targetIndices = projectTextToUtf16LexiconIndices(text, lexicon);
  const baselineIndices = options.baselineText
    ? projectTextToUtf16LexiconIndices(options.baselineText, lexicon)
    : null;
  return chooseTeleportPacket({
    targetIndices,
    baselineIndices,
    mode,
    reorderMode,
    tritonCompression,
  });
}

/**
 * Handles the gnosis inflate Utf16 From Teleport workflow.
 */
export async function inflateUtf16FromTeleport(
  packet: UnicodeTeleportPacket,
  lexicon: Utf16Lexicon,
  options: UnicodeInflationOptions = {}
): Promise<string> {
  const baselineIndices = options.baselineText
    ? projectTextToUtf16LexiconIndices(options.baselineText, lexicon)
    : null;
  const indices = await decodeTeleportPacketToIndices(packet, baselineIndices);
  for (const index of indices) {
    validateLexiconIndex(index, lexicon.codeUnits.length);
  }
  return inflateTextFromUtf16LexiconIndices(indices, lexicon);
}

/**
 * Builds the Unicode Structural Packet.
 */
export function buildUnicodeStructuralPacket(
  text: string,
  lexicon: UnicodeLexicon
): UnicodeStructuralPacket {
  const indices = projectTextToLexiconIndices(text, lexicon);
  return encodeStructuralPacketFromIndices(indices, lexicon.codePoints.length);
}

/**
 * Handles the gnosis inflate Unicode From Structural Packet workflow.
 */
export function inflateUnicodeFromStructuralPacket(
  packet: UnicodeStructuralPacket,
  lexicon: UnicodeLexicon
): string {
  const indices = decodeStructuralPacketToIndices(
    packet,
    lexicon.codePoints.length
  );
  return inflateTextFromLexiconIndices(indices, lexicon);
}

/**
 * Builds the Utf16 Structural Packet.
 */
export function buildUtf16StructuralPacket(
  text: string,
  lexicon: Utf16Lexicon
): UnicodeStructuralPacket {
  const indices = projectTextToUtf16LexiconIndices(text, lexicon);
  return encodeStructuralPacketFromIndices(indices, lexicon.codeUnits.length);
}

/**
 * Handles the gnosis inflate Utf16 From Structural Packet workflow.
 */
export function inflateUtf16FromStructuralPacket(
  packet: UnicodeStructuralPacket,
  lexicon: Utf16Lexicon
): string {
  const indices = decodeStructuralPacketToIndices(packet, lexicon.codeUnits.length);
  return inflateTextFromUtf16LexiconIndices(indices, lexicon);
}

function compareShootoutEntries(
  a: UnicodeTeleportShootoutEntry,
  b: UnicodeTeleportShootoutEntry
): number {
  if (a.estimatedPayloadBytes !== b.estimatedPayloadBytes) {
    return a.estimatedPayloadBytes - b.estimatedPayloadBytes;
  }
  return a.strategy.localeCompare(b.strategy);
}

/**
 * Handles the gnosis run Unicode Teleport Shootout workflow.
 */
export async function runUnicodeTeleportShootout(
  text: string,
  lexicon: UnicodeLexicon,
  options: UnicodeTeleportShootoutOptions = {}
): Promise<UnicodeTeleportShootoutResult> {
  const tritonCompression = options.tritonCompression ?? {
    motifSize: 5,
    useBitwiseFold: true,
    preferSmallerPayload: true,
  };
  const includeStructural = options.includeStructural ?? true;
  const includeReordered = options.includeReordered ?? true;

  const targetIndices = projectTextToLexiconIndices(text, lexicon);
  const entries: UnicodeTeleportShootoutEntry[] = [];

  const direct = await encodeDirectTeleportPacket(targetIndices, tritonCompression);
  entries.push({
    strategy: direct.strategy,
    estimatedPayloadBytes: direct.estimatedPayloadBytes,
    preservesOrder: true,
    packet: direct,
  });

  if (includeReordered) {
    const reordered = await encodeDirectReorderedTeleportPacket(
      targetIndices,
      tritonCompression
    );
    entries.push({
      strategy: reordered.strategy,
      estimatedPayloadBytes: reordered.estimatedPayloadBytes,
      preservesOrder: true,
      packet: reordered,
    });
  }

  if (options.baselineText) {
    const baselineIndices = projectTextToLexiconIndices(options.baselineText, lexicon);
    const residual = encodeResidualTeleportPacket(targetIndices, baselineIndices);
    entries.push({
      strategy: residual.strategy,
      estimatedPayloadBytes: residual.estimatedPayloadBytes,
      preservesOrder: true,
      packet: residual,
    });
  }

  if (includeStructural) {
    const structural = encodeStructuralPacketFromIndices(
      targetIndices,
      lexicon.codePoints.length
    );
    entries.push({
      strategy: structural.strategy,
      estimatedPayloadBytes: structural.estimatedPayloadBytes,
      preservesOrder: false,
      packet: structural,
    });
  }

  if (entries.length === 0) {
    throw new Error('shootout produced no entries');
  }

  const ordered = [...entries].sort(compareShootoutEntries);
  const bestAny = ordered[0]!;
  const bestLossless = ordered.find((entry) => entry.preservesOrder);
  if (!bestLossless) {
    throw new Error('shootout has no order-preserving strategy');
  }

  return {
    entries: ordered,
    bestLossless,
    bestAny,
  };
}
